#!/usr/bin/env node
/**
 * Walks projects/kitchen-sink/src/app/examples/, reads every <key>.example.ts
 * and optional sibling <key>.example.po, and emits
 * projects/kitchen-sink/src/app/examples/sources.generated.ts — a map of
 * source-key -> { ts, po? } consumed by LinguiExampleComponent's source-reveal
 * pane.
 *
 * The generated file is gitignored; this script runs via prebuild:demo +
 * prestart npm hooks.
 */
import { existsSync, readdirSync, readFileSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';

const root = new URL('..', import.meta.url).pathname;
const examplesDir = join(root, 'projects/kitchen-sink/src/app/examples');
const outputPath = join(examplesDir, 'sources.generated.ts');

const HEADER =
  '/* AUTO-GENERATED by scripts/generate-example-sources.mjs. DO NOT EDIT BY HAND. */\n' +
  'export type ExampleSources = { ts: string; po?: string };\n';

function emit(map) {
  const body =
    HEADER +
    'export const SOURCES: Record<string, ExampleSources> = ' +
    JSON.stringify(map, null, 2) +
    ';\n';
  writeFileSync(outputPath, body);
}

if (!existsSync(examplesDir)) {
  console.warn(
    `[generate-example-sources] examples/ not found at ${examplesDir} — skipping codegen (nothing to write).`,
  );
  process.exit(0);
}

const entries = readdirSync(examplesDir);
/** @type {Record<string, { ts?: string; po?: string }>} */
const grouped = {};

const SKIP_FILES = new Set(['index.ts', 'sources.generated.ts']);

for (const file of entries) {
  if (SKIP_FILES.has(file)) continue;
  // Group by key — filename before first dot, e.g. `basic.example.ts` -> `basic`.
  const dotIdx = file.indexOf('.');
  if (dotIdx <= 0) continue;
  const key = file.slice(0, dotIdx);
  const rest = file.slice(dotIdx + 1);

  let kind;
  if (rest === 'example.ts') kind = 'ts';
  else if (rest === 'example.po') kind = 'po';
  else continue;

  const filePath = join(examplesDir, file);
  const content = readFileSync(filePath, 'utf8');
  grouped[key] = grouped[key] || {};
  grouped[key][kind] = content;
}

// Final map: only include keys that have at least a .ts source.
/** @type {Record<string, { ts: string; po?: string }>} */
const map = {};
for (const [key, value] of Object.entries(grouped)) {
  if (!value.ts) continue;
  const entry = { ts: value.ts };
  if (value.po) entry.po = value.po;
  map[key] = entry;
}

const count = Object.keys(map).length;
if (count === 0) {
  console.warn(
    `[generate-example-sources] examples/ exists but contains no *.example.ts files — emitting empty SOURCES map.`,
  );
} else {
  console.log(
    `[generate-example-sources] wrote ${count} source entr${count === 1 ? 'y' : 'ies'} to sources.generated.ts`,
  );
}

emit(map);
process.exit(0);
